		assertEquals(JoinSearchContributor.Status.BUDGET_EXHAUSTED, exhaustive.outcome().status());
		assertEquals(JoinSearchCompleteness.BUDGET_EXHAUSTED, result.completeness());
		assertTrue(result.pendingReasons().stream().anyMatch(reason -> reason.contains("candidate budget")));
