	@Test
	void regionAndDependenciesAreDefensivelyImmutable() {
		ArrayList<JoinFactor> factors = new ArrayList<>(List.of(new JoinFactor(0), new JoinFactor(1)));
		HashSet<Integer> prerequisites = new HashSet<>(Set.of(0));
		ArrayList<JoinDependency> dependencies = new ArrayList<>(List.of(new JoinDependency(1, prerequisites)));
		JoinRegion region = new JoinRegion(factors, dependencies);

		factors.clear();
		prerequisites.clear();
		dependencies.clear();

		assertEquals(List.of(new JoinFactor(0), new JoinFactor(1)), region.factors());
		assertEquals(Set.of(0), region.requiredBefore(1));
		assertThrows(UnsupportedOperationException.class, () -> region.factors().add(new JoinFactor(2)));
		assertThrows(UnsupportedOperationException.class, () -> region.requiredBefore(1).add(2));
	}

	private static JoinSearchContributor contributor(String id, JoinSearchContributor.Coverage coverage,
			JoinTree tree) {
		return new JoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor(id, coverage, 100);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest ignored, CandidateSink sink) {
				sink.accept(tree);
				return Outcome.completed();
			}
		};
	}

	private static JoinSearchResult.Attempt attempt(JoinSearchResult result, String contributorId) {
		return result.attempts()
				.stream()
				.filter(candidate -> candidate.descriptor().id().equals(contributorId))
				.findFirst()
				.orElseThrow();
	}

	private static JoinRegion region(int factorCount, List<JoinDependency> dependencies) {
		ArrayList<JoinFactor> factors = new ArrayList<>(factorCount);
		for (int groupId = 0; groupId < factorCount; groupId++) {
			factors.add(new JoinFactor(groupId));
		}
		return new JoinRegion(factors, dependencies);
	}

	private static List<JoinDependency> dependencyChain(int factorCount) {
		ArrayList<JoinDependency> dependencies = new ArrayList<>();
		for (int occurrenceId = 1; occurrenceId < factorCount; occurrenceId++) {
			dependencies.add(new JoinDependency(occurrenceId, Set.of(occurrenceId - 1)));
		}
		return dependencies;
	}

	private static OracleWinner bruteForceWinner(JoinRegion region, JoinSearchCostModel costModel) {
		Map<Set<Integer>, List<JoinTree>> cache = new HashMap<>();
		List<JoinTree> allTrees = enumerateTrees(region.factorIds(), cache);
		return allTrees.stream()
				.filter(region::isLegal)
				.map(tree -> new OracleWinner(tree, evaluate(tree, region, costModel)))
				.min(Comparator.comparing(OracleWinner::cost)
						.thenComparing(winner -> winner.tree().canonicalForm()))
				.orElseThrow();
	}

	private static List<JoinTree> enumerateTrees(Set<Integer> factorIds, Map<Set<Integer>, List<JoinTree>> cache) {
		Set<Integer> key = Set.copyOf(factorIds);
		List<JoinTree> cached = cache.get(key);
		if (cached != null) {
			return cached;
		}
		if (factorIds.size() == 1) {
			List<JoinTree> singleton = List.of(JoinTree.factor(factorIds.iterator().next()));
			cache.put(key, singleton);
			return singleton;
		}
		List<Integer> ordered = factorIds.stream().sorted().toList();
		LinkedHashSet<JoinTree> trees = new LinkedHashSet<>();
		int partitionCount = 1 << ordered.size();
		for (int mask = 1; mask < partitionCount - 1; mask++) {
			Set<Integer> leftIds = new HashSet<>();
			Set<Integer> rightIds = new HashSet<>();
			for (int index = 0; index < ordered.size(); index++) {
				(maskContains(mask, index) ? leftIds : rightIds).add(ordered.get(index));
			}
			for (JoinTree left : enumerateTrees(leftIds, cache)) {
				for (JoinTree right : enumerateTrees(rightIds, cache)) {
					trees.add(JoinTree.join(left, right));
				}
			}
		}
		List<JoinTree> result = List.copyOf(trees);
		cache.put(key, result);
		return result;
	}

	private static boolean maskContains(int mask, int index) {
		return (mask & (1 << index)) != 0;
	}

	private static JoinSearchCost evaluate(JoinTree tree, JoinRegion region, JoinSearchCostModel costModel) {
		if (tree instanceof JoinTree.Factor factor) {
			JoinSearchEstimate estimate = costModel.estimateFactor(region.factor(factor.occurrenceId()));
			return new JoinSearchCost(estimate.outputRows(), estimate.localWork());
		}
		JoinTree.Join join = (JoinTree.Join) tree;
		JoinSearchCost left = evaluate(join.left(), region, costModel);
		JoinSearchCost right = evaluate(join.right(), region, costModel);
		JoinSearchEstimate local = costModel.estimateJoin(join.left(), left, join.right(), right);
		return new JoinSearchCost(local.outputRows(), left.totalWork() + right.totalWork() + local.localWork());
	}

	private record OracleWinner(JoinTree tree, JoinSearchCost cost) {
		private OracleWinner {
			assertNotNull(tree);
			assertNotNull(cost);
		}
	}
